type SidebarNavIconProps = {
  icon: LucideIcon;
  className?: string;
};

/**
 * Sidebar navigation icon (Lucide) with light/dual-tone treatment for the
 * management sidebar. Sits inside `SidebarMenuButton`.
 */
const SidebarNavIcon = React.memo(function SidebarNavIcon({
  icon: Icon,
  className,
}: SidebarNavIconProps) {
  const stroke = iconStroke(16);
  return (
    <span
      className={`inline-flex shrink-0 items-center justify-center transition-colors duration-200 [&_svg]:size-4 [&_svg]:shrink-0 ${className ?? ""}`}
    >
      <Icon
        strokeWidth={stroke}
        className="text-[color:var(--color-brand-primary-700,var(--primary))] dark:hidden"
      />
      <Icon
        strokeWidth={stroke}
        className="hidden text-[color:var(--color-brand-accent-300,var(--ring))] dark:inline-block"
      />
    </span>
  );
});

