"use client";

import * as React from "react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

export type SnackbarData = {
  id: string;
  title: string;
  message?: string;
  variant?: "default" | "destructive";
  duration?: number;
};

export type SnackbarProps = SnackbarData & {
  className?: string;
  onDismiss: (id: string) => void;
};

export function Snackbar({
  id,
  title,
  message,
  variant = "default",
  className,
  onDismiss,
}: SnackbarProps) {
  return (
    <div
      role="status"
      className={cn(
        "rounded-lg border bg-card p-4 text-card-foreground shadow-lg",
        variant === "destructive" && "border-destructive/50 bg-destructive/10 text-destructive-foreground",
        className,
      )}
    >
      <div className="flex items-start justify-between gap-3">
        <div className="min-w-0">
          <p className="font-medium">{title}</p>
          {message ? <p className="mt-1 text-sm text-muted-foreground">{message}</p> : null}
        </div>
        <Button type="button" variant="ghost" size="icon-xs" onClick={() => onDismiss(id)} aria-label="Dismiss">
          ×
        </Button>
      </div>
    </div>
  );
}

"use client";

import * as React from "react";

import type { SnackbarData } from "./Snackbar";

export type SnackbarContextType = {
  addSnackbar: (data: Omit<SnackbarData, "id"> & { id?: string }) => string;
  removeSnackbar: (id: string) => void;
  snackbars: SnackbarData[];
};

const SnackbarContext = React.createContext<SnackbarContextType | undefined>(undefined);

function createId() {
  return `snackbar-${Math.random().toString(36).slice(2, 11)}`;
}

export function SnackbarProvider({ children }: { children: React.ReactNode }) {
  const [snackbars, setSnackbars] = React.useState<SnackbarData[]>([]);

  const removeSnackbar = React.useCallback((id: string) => {
    setSnackbars((prev) => prev.filter((s) => s.id !== id));
  }, []);

  const addSnackbar = React.useCallback(
    (data: Omit<SnackbarData, "id"> & { id?: string }) => {
      const id = data.id ?? createId();
      const entry: SnackbarData = {
        id,
        title: data.title,
        message: data.message,
        variant: data.variant,
        duration: data.duration,
      };
      setSnackbars((prev) => [...prev, entry]);
      const duration = data.duration ?? 5000;
      if (duration > 0) {
        window.setTimeout(() => removeSnackbar(id), duration);
      }
      return id;
    },
    [removeSnackbar],
  );

  const value = React.useMemo(
    () => ({ addSnackbar, removeSnackbar, snackbars }),
    [addSnackbar, removeSnackbar, snackbars],
  );

  return <SnackbarContext.Provider value={value}>{children}</SnackbarContext.Provider>;
}

export function useSnackbar(): SnackbarContextType {
  const ctx = React.useContext(SnackbarContext);
  if (!ctx) {
    throw new Error("useSnackbar must be used within SnackbarProvider");
  }
  return ctx;
}

export * from "./Snackbar";
export * from "./SnackbarProvider";
export * from "./SnackbarContainer";

