export type PrimaryNavItem = {
	key: string;
	title: string;
	url: string;
	icon: LucideIcon;
};

export const ESTATE_PRIMARY_NAV: readonly PrimaryNavItem[] = [
	{
		key: "dashboard",
		title: "Plot rankings",
		url: "/plots",
		icon: LayoutDashboard,
	},
	{
		key: "scoring",
		title: "Scoring rules",
		url: "/config",
		icon: SlidersHorizontal,
	},
	{
		key: "data",
		title: "Data & settings",
		url: "/import-export",
		icon: Settings,
	},
] as const;

export const ESTATE_SECONDARY_NAV: readonly PrimaryNavItem[] = [
	{
		key: "about",
		title: "About",
		url: "/about",
		icon: CircleHelp,
	},
] as const;

export function isPrimaryNavActive(itemUrl: string, pathname: string): boolean {
	const normalized = pathname.endsWith("/") && pathname !== "/"
		? pathname.slice(0, -1)
		: pathname;
	const item = itemUrl.endsWith("/") && itemUrl !== "/"
		? itemUrl.slice(0, -1)
		: itemUrl;

	if (item === "/plots") {
		return (
			normalized === "/plots" || normalized.startsWith("/plots/")
		);
	}

	return normalized === item;
}

export function breadcrumbTitleForPath(pathname: string): string {
	const normalized = pathname.endsWith("/") && pathname !== "/"
		? pathname.slice(0, -1)
		: pathname;

	if (normalized === "/plots" || normalized.startsWith("/plots/")) {
		if (normalized.startsWith("/plots/") && normalized !== "/plots") {
			return "Plot detail";
		}
		return "Plot rankings";
	}
	if (normalized === "/config") {
		return "Scoring rules";
	}
	if (normalized === "/import-export") {
		return "Data & settings";
	}
	if (normalized === "/about") {
		return "About";
	}
	if (normalized === "/") {
		return "Home";
	}
	return "Workspace";
}

