import type {
	PersistenceLayer,
	SerializableProps,
} from "@portugal/ui";
import { getRouteApi } from "@tanstack/react-router";
import { useCallback, useEffect, useMemo, useRef } from "react";

import type { EstateRootSearch } from "../search/estate-root-search";

const rootRouteApi = getRouteApi("__root__");

function splitPanelTypes(panels: string | undefined): string[] {
	if (!panels) {
		return [];
	}
	return panels.split(",").filter(Boolean);
}

/**
 * URL search persistence for sewdn `PanelsLayout`, using TanStack Router root
 * `validateSearch` fields (`panels`, `activePanel`, `panelProps`).
 */
export function useTanstackPanelPersistence(): PersistenceLayer {
	const search = rootRouteApi.useSearch();
	const navigate = rootRouteApi.useNavigate();

	const openPanelTypes = useMemo(
		() => splitPanelTypes(search.panels),
		[search.panels],
	);
	const activePanelType = search.activePanel ?? null;

	const panelPropsMap = useMemo((): Record<string, SerializableProps> => {
		if (!search.panelProps) {
			return {};
		}
		try {
			return JSON.parse(search.panelProps) as Record<string, SerializableProps>;
		} catch (e) {
			console.error("Error parsing panel props from URL search", e);
			return {};
		}
	}, [search.panelProps]);

	const stateRef = useRef({
		openPanelTypes,
		activePanelType,
		panelPropsMap,
	});

	useEffect(() => {
		stateRef.current = {
			openPanelTypes,
			activePanelType,
			panelPropsMap,
		};
	}, [activePanelType, openPanelTypes, panelPropsMap]);

	const getOpenPanelTypes = useCallback(() => openPanelTypes, [openPanelTypes]);
	const getActivePanelType = useCallback(
		() => activePanelType,
		[activePanelType],
	);
	const getPanelPropsMap = useCallback(() => panelPropsMap, [panelPropsMap]);

	const updateUrl = useCallback(
		(
			newTypes: string[],
			newActiveType: string | null,
			newPropsMap: Record<string, SerializableProps>,
		) => {
			const sanitizedPropsMap = JSON.parse(
				JSON.stringify(newPropsMap),
			) as Record<string, SerializableProps>;

			void navigate({
				search: (prev: EstateRootSearch) => {
					const next: EstateRootSearch = { ...prev };
					if (newTypes.length > 0) {
						next.panels = newTypes.join(",");
					} else {
						delete next.panels;
					}
					if (newActiveType) {
						next.activePanel = newActiveType;
					} else {
						delete next.activePanel;
					}
					if (Object.keys(sanitizedPropsMap).length > 0) {
						next.panelProps = JSON.stringify(sanitizedPropsMap);
					} else {
						delete next.panelProps;
					}
					return next;
				},
				replace: true,
			});
		},
		[navigate],
	);

	const setOpenPanelTypes = useCallback(
		(types: string[]) => {
			stateRef.current = { ...stateRef.current, openPanelTypes: types };
			updateUrl(
				types,
				stateRef.current.activePanelType,
				stateRef.current.panelPropsMap,
			);
		},
		[updateUrl],
	);

	const setPanelPropsMap = useCallback(
		(propsMap: Record<string, SerializableProps>) => {
			stateRef.current = { ...stateRef.current, panelPropsMap: propsMap };
			updateUrl(
				stateRef.current.openPanelTypes,
				stateRef.current.activePanelType,
				propsMap,
			);
		},
		[updateUrl],
	);

	const setActivePanelType = useCallback(
		(type: string | null) => {
			stateRef.current = { ...stateRef.current, activePanelType: type };
			updateUrl(stateRef.current.openPanelTypes, type, stateRef.current.panelPropsMap);
		},
		[updateUrl],
	);

	const subscribe = useCallback((_callback: () => void) => () => {}, []);

	return useMemo(
		() => ({
			getOpenPanelTypes,
			getPanelPropsMap,
			getActivePanelType,
			setOpenPanelTypes,
			setPanelPropsMap,
			setActivePanelType,
			subscribe,
		}),
		[
			getOpenPanelTypes,
			getPanelPropsMap,
			getActivePanelType,
			setOpenPanelTypes,
			setPanelPropsMap,
			setActivePanelType,
			subscribe,
		],
	);
}

