/** Side panel: plot record + scores (deal view). */
export const PLOT_DEAL_PANEL_TYPE = "plot-deal";

/** Side panel: investment profile + weights (deal view). */
export const PROFILE_DEAL_PANEL_TYPE = "profile-deal";

/** Side panel: criterion definition + per-profile weights (deal view). */
export const CRITERION_DEAL_PANEL_TYPE = "criterion-deal";

/** Side panel: quick help / shortcuts. */
export const HELP_PANEL_TYPE = "help";

import type { AppSnapshot } from "@portugal/domain-shared";
import { useEffect, useState } from "react";

import { loadSnapshot } from "../lib/plot-storage";

export function usePanelSnapshot(): {
	snapshot: AppSnapshot | null;
	loading: boolean;
	error: string | null;
} {
	const [snapshot, setSnapshot] = useState<AppSnapshot | null>(null);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState<string | null>(null);

	useEffect(() => {
		let cancelled = false;
		setLoading(true);
		setError(null);
		void loadSnapshot()
			.then((loaded) => {
				if (!cancelled) {
					setSnapshot(loaded);
				}
			})
			.catch(() => {
				if (!cancelled) {
					setError("Could not load data.");
					setSnapshot(null);
				}
			})
			.finally(() => {
				if (!cancelled) {
					setLoading(false);
				}
			});
		return () => {
			cancelled = true;
		};
	}, []);

	return { snapshot, loading, error };
}

import { Card, CardContent, CardHeader, CardTitle, IconButton, usePanelsContext } from "@portugal/ui";
import { X } from "lucide-react";

export function DealPanelCloseButton({ panelType }: { panelType: string }) {
