}) {
	return (
		<Card className="border-0 bg-transparent shadow-none">
			<CardHeader className="flex flex-row items-start justify-between gap-2 space-y-0 pb-2">
				<CardTitle className="text-base font-semibold leading-snug">{title}</CardTitle>
				<DealPanelCloseButton panelType={panelType} />
			</CardHeader>
			<CardContent className="max-h-[min(70vh,560px)] space-y-4 overflow-y-auto pr-1 text-sm">
				{children}
			</CardContent>
		</Card>
	);
}

import type { ScoringRule } from "@portugal/domain-shared";

function formatNumericBands(rule: Extract<ScoringRule, { type: "numeric" }>): string {
	return rule.bands
		.map((b, i) => {
			const min =
				b.minInclusive !== undefined ? `[${b.minInclusive}` : "(-∞";
			const max =
				b.maxExclusive !== undefined ? `${b.maxExclusive})` : "∞)";
			return `Band ${i + 1}: ${min} … ${max} → score ${b.score}`;
		})
		.join("\n");
}

function formatQualitative(rule: Extract<ScoringRule, { type: "qualitative" }>): string {
	return Object.entries(rule.mapping)
		.map(([k, v]) => `${k}: ${v}`)
		.join("\n");
}

function formatMultiSelect(rule: Extract<ScoringRule, { type: "multi_select" }>): string {
	const lines = Object.entries(rule.mapping).map(([k, v]) => `${k}: ${v}`);
	return [`Aggregation: ${rule.aggregation}`, ...lines].join("\n");
}

/** Readable summary of a scoring rule for deal panels. */
export function scoringRuleSummary(rule: ScoringRule): string {
	switch (rule.type) {
		case "numeric":
			return formatNumericBands(rule);
		case "qualitative":
			return formatQualitative(rule);
		case "multi_select":
			return formatMultiSelect(rule);
		default:
			return JSON.stringify(rule);
	}
}

