					No profile found for id <span className="font-mono">{profileId}</span>.
				</p>
			</DealPanelShell>
		);
	}

	const weights = snapshot.activeConfig.profileWeights[profileId] ?? {};
	const criteriaById = new Map(
		snapshot.activeConfig.criteria.map((c) => [c.id, c] as const),
