				</p>
				<p className="mt-1 text-[11px] text-muted-foreground">
					Weights are stored per profile in{" "}
					<code className="rounded bg-muted px-1">profileWeights</code>; they should sum
					to 1 per profile in a valid config.
				</p>
				<ul className="mt-2 max-h-64 space-y-1 overflow-y-auto pr-1">
					{snapshot.activeConfig.criteria.map((criterion) => {
						const w = weights[criterion.id] ?? 0;
						return (
							<li
								key={criterion.id}
								className="flex justify-between gap-2 rounded-md bg-muted/25 px-2 py-1 text-xs tabular-nums"
							>
								<span className="min-w-0 truncate">{criterion.name}</span>
								<span className="shrink-0 font-medium">{w.toFixed(3)}</span>
							</li>
						);
					})}
				</ul>
			</div>

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Linked criterion definitions
				</p>
				<ul className="mt-2 space-y-1 text-[11px] text-muted-foreground">
					{snapshot.activeConfig.criteria.map((c) => (
						<li key={c.id}>
							<span className="font-medium text-foreground">{c.name}</span>
