import type { PlotRawMetricValue } from "@portugal/domain-shared";
import { computePlotScores } from "@portugal/domain-shared";
import { Separator } from "@portugal/ui";

import { DetailPanelShell } from "./detail-panel-chrome";
import { PLOT_DETAIL_PANEL_TYPE } from "./panel-types";
import { usePanelSnapshot } from "./use-panel-snapshot";

export type PlotDetailPanelProps = {
	panelType?: string;
	plotId?: string;
};

function formatRawMetricValue(value: PlotRawMetricValue): string {
	if (typeof value === "number") {
		return String(value);
	}
	if (typeof value === "string") {
		return value;
	}
	if (Array.isArray(value)) {
		return value.join(", ");
	}
	return "—";
}

export function PlotDetailPanel({
	panelType = PLOT_DETAIL_PANEL_TYPE,
	plotId: plotIdProp,
}: PlotDetailPanelProps) {
	const plotId =
		typeof plotIdProp === "string" && plotIdProp.length > 0
			? plotIdProp
			: undefined;
	const { snapshot, loading, error } = usePanelSnapshot();

	if (loading) {
		return (
			<DetailPanelShell title="Plot details" panelType={panelType}>
				<p className="text-muted-foreground">Loading…</p>
			</DetailPanelShell>
		);
	}

	if (error || !snapshot) {
		return (
			<DetailPanelShell title="Plot details" panelType={panelType}>
				<p className="text-destructive">{error ?? "No data."}</p>
			</DetailPanelShell>
		);
	}

	const plot = plotId ? snapshot.plots.find((p) => p.id === plotId) : undefined;

	if (!plotId) {
		return (
			<DetailPanelShell title="Plot details" panelType={panelType}>
				<p className="text-muted-foreground">No plot selected.</p>
			</DetailPanelShell>
		);
	}

	if (!plot) {
		return (
			<DetailPanelShell title="Plot details" panelType={panelType}>
				<p className="text-muted-foreground">
					No plot found for id <span className="font-mono">{plotId}</span>.
				</p>
			</DetailPanelShell>
		);
	}

	const scores = computePlotScores(snapshot.activeConfig, plot.rawMetrics);
	const cfg = snapshot.activeConfig;

	return (
		<DetailPanelShell title={plot.name} panelType={panelType}>
			<dl className="grid gap-2 text-xs sm:grid-cols-2">
				<dt className="text-muted-foreground">Address</dt>
				<dd className="font-medium">{plot.address || "—"}</dd>
				<dt className="text-muted-foreground">Region</dt>
				<dd>{plot.region ?? "—"}</dd>
				<dt className="text-muted-foreground">Municipality</dt>
				<dd>{plot.municipality ?? "—"}</dd>
				<dt className="text-muted-foreground">Asking (EUR)</dt>
				<dd>
					{plot.askingPriceEur !== undefined
						? plot.askingPriceEur.toLocaleString()
						: "—"}
				</dd>
				<dt className="text-muted-foreground">KO status</dt>
				<dd>{plot.koStatus ?? "—"}</dd>
				<dt className="text-muted-foreground">Buildable</dt>
				<dd>
					{plot.buildableYn === undefined
						? "—"
						: plot.buildableYn
							? "Yes"
							: "No"}
				</dd>
				<dt className="text-muted-foreground">Road access</dt>
				<dd>
					{plot.roadAccessYn === undefined
						? "—"
						: plot.roadAccessYn
							? "Yes"
							: "No"}
				</dd>
				<dt className="text-muted-foreground">Basic utilities</dt>
				<dd>
					{plot.utilitiesBasicYn === undefined
						? "—"
						: plot.utilitiesBasicYn
							? "Yes"
							: "No"}
				</dd>
			</dl>
			{plot.notes ? (
				<div>
					<p className="text-xs font-medium text-muted-foreground">Notes</p>
					<p className="mt-1 whitespace-pre-wrap text-foreground/90">
						{plot.notes}
					</p>
				</div>
			) : null}

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Profile scores
				</p>
				<ul className="mt-2 space-y-1">
					{cfg.profiles.map((profile) => {
						const pct = scores.profileScores[profile.id]?.percentage ?? 0;
						return (
							<li
								key={profile.id}
								className="flex justify-between gap-2 text-xs tabular-nums"
							>
								<span className="truncate">{profile.name}</span>
								<span className="shrink-0 font-medium">
									{(pct / 20).toFixed(2)} / 5
								</span>
							</li>
						);
					})}
				</ul>
			</div>

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Raw metrics by criterion
				</p>
				<ul className="mt-2 space-y-2">
					{cfg.criteria.map((criterion) => {
						const raw = plot.rawMetrics[criterion.id];
						return (
							<li
								key={criterion.id}
								className="rounded-md bg-muted/30 px-2 py-1.5 text-xs"
							>
								<div className="font-medium text-foreground">
									{criterion.name}
								</div>
								<div className="text-muted-foreground">
									{criterion.measurementBasis}
								</div>
								<div className="mt-0.5 font-mono text-[11px] text-foreground/90">
									{raw === undefined ? "—" : formatRawMetricValue(raw)}
								</div>
							</li>
						);
					})}
				</ul>
			</div>
		</DetailPanelShell>
	);
}

