export function ProfileDetailPanel({
	panelType = PROFILE_DETAIL_PANEL_TYPE,
	profileId: profileIdProp,
}: ProfileDetailPanelProps) {
	const profileId =
		typeof profileIdProp === "string" && profileIdProp.length > 0
			? profileIdProp
			: undefined;
	const { snapshot, loading, error } = usePanelSnapshot();

	if (loading) {
		return (
			<DetailPanelShell title="Investment profile" panelType={panelType}>
				<p className="text-muted-foreground">Loading…</p>
			</DetailPanelShell>
		);
	}

	if (error || !snapshot) {
		return (
			<DetailPanelShell title="Investment profile" panelType={panelType}>
				<p className="text-destructive">{error ?? "No data."}</p>
			</DetailPanelShell>
		);
	}

	if (!profileId) {
		return (
			<DetailPanelShell title="Investment profile" panelType={panelType}>
				<p className="text-muted-foreground">No profile selected.</p>
			</DetailPanelShell>
		);
	}

	const profile = snapshot.activeConfig.profiles.find(
		(p) => p.id === profileId,
	);
	if (!profile) {
		return (
			<DetailPanelShell title="Investment profile" panelType={panelType}>
				<p className="text-muted-foreground">
					No profile found for id <span className="font-mono">{profileId}</span>
					.
				</p>
			</DetailPanelShell>
		);
	}

	const weights = snapshot.activeConfig.profileWeights[profileId] ?? {};
	const criteriaById = new Map(
		snapshot.activeConfig.criteria.map((c) => [c.id, c] as const),
	);

	return (
		<DetailPanelShell title={profile.name} panelType={panelType}>
			<dl className="grid gap-2 text-xs">
				<dt className="text-muted-foreground">Code</dt>
				<dd className="font-mono">{profile.code}</dd>
				<dt className="text-muted-foreground">Description</dt>
				<dd className="text-foreground/90">{profile.description}</dd>
				<dt className="text-muted-foreground">Id</dt>
				<dd className="font-mono text-[11px]">{profile.id}</dd>
			</dl>

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Criterion weights (this profile)
				</p>
				<p className="mt-1 text-[11px] text-muted-foreground">
					Weights are stored per profile in{" "}
					<code className="rounded bg-muted px-1">profileWeights</code>; they
					should sum to 1 per profile in a valid config.
				</p>
				<ul className="mt-2 max-h-64 space-y-1 overflow-y-auto pr-1">
					{snapshot.activeConfig.criteria.map((criterion) => {
						const w = weights[criterion.id] ?? 0;
						return (
							<li
								key={criterion.id}
								className="flex justify-between gap-2 rounded-md bg-muted/25 px-2 py-1 text-xs tabular-nums"
							>
								<span className="min-w-0 truncate">{criterion.name}</span>
								<span className="shrink-0 font-medium">{w.toFixed(3)}</span>
							</li>
						);
					})}
				</ul>
			</div>

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Linked criteria
				</p>
				<ul className="mt-2 space-y-1 text-[11px] text-muted-foreground">
					{snapshot.activeConfig.criteria.map((c) => (
						<li key={c.id}>
							<span className="font-medium text-foreground">{c.name}</span>
							{" · "}
							{criteriaById.get(c.id)?.measurementBasis}
						</li>
					))}
				</ul>
			</div>
		</DetailPanelShell>
	);
}

