import { useCallback, useEffect, useMemo, useRef } from 'react';

import type { PersistenceLayer, SerializableProps } from './persistence';

/** Query key: comma-separated open panel type ids. */
export const PANELS_URL_TYPES_PARAM = 'panels';

/** Query key: active (focused) panel type id. */
export const PANELS_URL_ACTIVE_PARAM = 'activePanel';

/** Query key: JSON map of panel type → serializable props. */
export const PANELS_URL_PROPS_PARAM = 'panelProps';

export type PanelsLayoutUrlPersistenceDeps = {
  /**
   * Current location search, e.g. `location.search` from React Router or TanStack Router
   * (typically includes a leading `?`).
   */
  search: string;
  /**
   * Persist the full query string after panel keys are merged into the current search.
   * Receives a `URLSearchParams` that already includes non-panel keys from `search`.
   */
  commitSearchParams: (params: URLSearchParams) => void;
};

function parseSearchString(search: string): URLSearchParams {
  const trimmed = search.startsWith('?') ? search.slice(1) : search;
  return new URLSearchParams(trimmed);
}

/**
 * Router-agnostic URL persistence for {@link PanelsLayout} / {@link PanelsProvider}:
 * reads and writes `panels`, `activePanel`, and `panelProps` query parameters.
 *
 * For React Router, use {@link useUrlQueryPersistence} from `./persistence`.
 * For TanStack Router (or others), pass `search` + `commitSearchParams` from your router.
 */
export function usePanelsLayoutUrlPersistence(
  deps: PanelsLayoutUrlPersistenceDeps
): PersistenceLayer {
  const { search, commitSearchParams } = deps;

  const { openPanelTypes, activePanelType, panelPropsMap } = useMemo(() => {
    const params = parseSearchString(search);
    const typeString = params.get(PANELS_URL_TYPES_PARAM);
    const types = typeString ? typeString.split(',').filter(Boolean) : [];
    const activeType = params.get(PANELS_URL_ACTIVE_PARAM) || null;
    const propsString = params.get(PANELS_URL_PROPS_PARAM);
    let propsMap: Record<string, SerializableProps> = {};

    if (propsString) {
      try {
        propsMap = JSON.parse(propsString) as Record<string, SerializableProps>;
      } catch (error) {
        console.error('Error parsing panel props from URL query', error);
      }
    }

    return { openPanelTypes: types, activePanelType: activeType, panelPropsMap: propsMap };
  }, [search]);

  const stateRef = useRef({
    openPanelTypes,
    activePanelType,
    panelPropsMap,
  });

  useEffect(() => {
    stateRef.current = {
      openPanelTypes,
      activePanelType,
      panelPropsMap,
    };
  }, [activePanelType, openPanelTypes, panelPropsMap]);

  const getOpenPanelTypes = useCallback(() => openPanelTypes, [openPanelTypes]);
  const getActivePanelType = useCallback(() => activePanelType, [activePanelType]);
  const getPanelPropsMap = useCallback(() => panelPropsMap, [panelPropsMap]);

  const updateUrl = useCallback(
    (
      newTypes: string[],
      newActiveType: string | null,
      newPropsMap: Record<string, SerializableProps>
    ) => {
      const params = parseSearchString(search);
      if (newTypes.length > 0) {
        params.set(PANELS_URL_TYPES_PARAM, newTypes.join(','));
      } else {
        params.delete(PANELS_URL_TYPES_PARAM);
      }
      if (newActiveType) {
        params.set(PANELS_URL_ACTIVE_PARAM, newActiveType);
      } else {
        params.delete(PANELS_URL_ACTIVE_PARAM);
      }

      const sanitizedPropsMap = JSON.parse(JSON.stringify(newPropsMap)) as Record<
        string,
        SerializableProps
      >;
      if (Object.keys(sanitizedPropsMap).length > 0) {
        params.set(PANELS_URL_PROPS_PARAM, JSON.stringify(sanitizedPropsMap));
      } else {
        params.delete(PANELS_URL_PROPS_PARAM);
      }

      commitSearchParams(params);
    },
    [commitSearchParams, search]
  );

  const setOpenPanelTypes = useCallback(
    (types: string[]) => {
      stateRef.current = { ...stateRef.current, openPanelTypes: types };
      updateUrl(types, stateRef.current.activePanelType, stateRef.current.panelPropsMap);
    },
    [updateUrl]
  );

  const setPanelPropsMap = useCallback(
    (propsMap: Record<string, SerializableProps>) => {
      stateRef.current = { ...stateRef.current, panelPropsMap: propsMap };
      updateUrl(stateRef.current.openPanelTypes, stateRef.current.activePanelType, propsMap);
    },
    [updateUrl]
  );

  const setActivePanelType = useCallback(
    (type: string | null) => {
      stateRef.current = { ...stateRef.current, activePanelType: type };
      updateUrl(stateRef.current.openPanelTypes, type, stateRef.current.panelPropsMap);
    },
    [updateUrl]
  );

  const subscribe = useCallback((_callback: () => void) => () => {}, []);

  return useMemo(
    () => ({
      getOpenPanelTypes,
      getPanelPropsMap,
      getActivePanelType,
      setOpenPanelTypes,
      setPanelPropsMap,
      setActivePanelType,
      subscribe,
    }),
    [
      getOpenPanelTypes,
      getPanelPropsMap,
      getActivePanelType,
      setOpenPanelTypes,
      setPanelPropsMap,
      setActivePanelType,
      subscribe,
    ]
  );
}

