import {
	PANELS_URL_ACTIVE_PARAM,
	PANELS_URL_PROPS_PARAM,
	PANELS_URL_TYPES_PARAM,
	usePanelsLayoutUrlPersistence,
} from "@portugal/ui";
import { getRouteApi } from "@tanstack/react-router";
import { useCallback } from "react";

import type { EstateRootSearch } from "../search/estate-root-search";

const rootRouteApi = getRouteApi("__root__");

/**
 * URL search persistence for sewdn `PanelsLayout`, using TanStack Router root
 * `validateSearch` fields (`panels`, `activePanel`, `panelProps`).
 */
export function useTanstackPanelPersistence() {
	const search = rootRouteApi.useRouterState({
		select: (s) => s.location.search,
	});
	const navigate = rootRouteApi.useNavigate();

	const commitSearchParams = useCallback(
		(params: URLSearchParams) => {
			void navigate({
				search: (prev: EstateRootSearch) => {
					const next: EstateRootSearch = { ...prev };
					const types = params.get(PANELS_URL_TYPES_PARAM);
					if (types) {
						next.panels = types;
					} else {
						delete next.panels;
					}
					const active = params.get(PANELS_URL_ACTIVE_PARAM);
					if (active) {
						next.activePanel = active;
					} else {
						delete next.activePanel;
					}
					const props = params.get(PANELS_URL_PROPS_PARAM);
					if (props) {
						next.panelProps = props;
					} else {
						delete next.panelProps;
					}
					return next;
				},
				replace: true,
			});
		},
		[navigate],
	);

	return usePanelsLayoutUrlPersistence({ search, commitSearchParams });
}

