import type { PlotRawMetrics } from "@portugal/domain-shared";

const STORAGE_KEY = "portugal-plot-scoring-raw-metrics-overlay";

const isRecord = (value: unknown): value is Record<string, unknown> =>
	typeof value === "object" && value !== null;

/**
 * User-entered raw metrics persisted in `localStorage` until export.
 * Merged under bundled/IndexedDB plot data: values in the plot record win
 * when the same criterion key exists in both places.
 */
export function readRawMetricsOverlay(): Record<string, PlotRawMetrics> {
	if (typeof window === "undefined") {
		return {};
	}
	try {
		const raw = window.localStorage.getItem(STORAGE_KEY);
		if (!raw) {
			return {};
		}
		const parsed: unknown = JSON.parse(raw);
		if (!isRecord(parsed)) {
			return {};
		}
		const out: Record<string, PlotRawMetrics> = {};
		for (const [plotId, value] of Object.entries(parsed)) {
			if (isRecord(value)) {
				out[plotId] = value as PlotRawMetrics;
			}
		}
		return out;
	} catch {
		return {};
	}
}

export function writeRawMetricsOverlay(overlay: Record<string, PlotRawMetrics>): void {
	if (typeof window === "undefined") {
		return;
	}
	window.localStorage.setItem(STORAGE_KEY, JSON.stringify(overlay));
}

/** Overlay fills missing keys; `bundle` (seed / IndexedDB) wins on conflicts. */
export function mergePlotRawMetricsFromOverlay(plotId: string, bundle: PlotRawMetrics): PlotRawMetrics {
	const overlay = readRawMetricsOverlay()[plotId] ?? {};
	return { ...overlay, ...bundle };
}

/** Mirror current effective raw metrics for all plots (call after persisting snapshot). */
export function syncRawMetricsOverlayFromPlots(
	plots: readonly { id: string; rawMetrics: PlotRawMetrics }[],
): void {
	const current = readRawMetricsOverlay();
	const next: Record<string, PlotRawMetrics> = { ...current };
	for (const p of plots) {
		next[p.id] = { ...p.rawMetrics };
	}
	writeRawMetricsOverlay(next);
}

export function removePlotFromRawMetricsOverlay(plotId: string): void {
	const current = readRawMetricsOverlay();
	if (!(plotId in current)) {
		return;
	}
	const { [plotId]: _removed, ...rest } = current;
	writeRawMetricsOverlay(rest);
}

