import type {
	CriterionId,
	ProfileWeights,
	ScoringConfig,
} from "@portugal/domain-shared";

/** Shared marble budget: every profile’s criterion weights sum to this total (interoperable scores). */
export const MARBLE_TARGET = 117;

export function sumProfileWeights(weights: ProfileWeights): number {
	return Object.values(weights).reduce((a, b) => a + (typeof b === "number" && !Number.isNaN(b) ? b : 0), 0);
}

/**
 * Integer-normalize weights so they sum exactly to `target`.
 * Preserves relative proportions; uses largest-remainder for the last unit of rounding.
 */
export function normalizeWeightsToSum(
	weights: ProfileWeights,
	criterionIds: readonly CriterionId[],
	target: number,
): ProfileWeights {
	const ids = criterionIds.filter((id) => id in weights || weights[id] !== undefined);
	const keys = criterionIds.length > 0 ? [...criterionIds] : (Object.keys(weights) as CriterionId[]);
	if (keys.length === 0) {
		return {};
	}
	const raw = keys.map((id) => ({
		id,
		w: Math.max(0, Number(weights[id]) || 0),
	}));
	const s = raw.reduce((a, x) => a + x.w, 0);
	if (s <= 0) {
		const base = Math.floor(target / keys.length);
		let rem = target - base * keys.length;
		const out: ProfileWeights = {};
		for (const id of keys) {
			out[id] = base + (rem > 0 ? 1 : 0);
			if (rem > 0) rem -= 1;
		}
		return out;
	}
	const scaled = raw.map((x) => ({ id: x.id, v: (x.w * target) / s }));
	const floors = scaled.map((x) => ({
		id: x.id,
		v: Math.max(0, Math.floor(x.v)),
	}));
	let sum = floors.reduce((a, x) => a + x.v, 0);
	let remainder = target - sum;
	const frac = scaled.map((x, i) => ({
		id: x.id,
		f: x.v - floors[i].v,
	}));
	frac.sort((a, b) => b.f - a.f);
	const bump = new Set(frac.slice(0, Math.max(0, remainder)).map((x) => x.id));
	const out: ProfileWeights = {};
	for (const x of floors) {
		out[x.id] = x.v + (bump.has(x.id) ? 1 : 0);
	}
	sum = Object.values(out).reduce((a, b) => a + b, 0);
	remainder = target - sum;
	if (remainder !== 0) {
		const firstId = keys[0];
		if (firstId) {
			out[firstId] = (out[firstId] ?? 0) + remainder;
		}
	}
	return out;
}

/** Rescale every profile so each sums to {@link MARBLE_TARGET}. */
export function normalizeAllProfileWeightsToMarbleTarget(
	config: ScoringConfig,
): ScoringConfig["profileWeights"] {
	const criterionIds = config.criteria.map((c) => c.id);
	const next: ScoringConfig["profileWeights"] = { ...config.profileWeights };
	for (const profile of config.profiles) {
		const w = config.profileWeights[profile.id] ?? {};
		const filled: ProfileWeights = {};
		for (const id of criterionIds) {
			filled[id] = w[id] ?? 1;
		}
		next[profile.id] = normalizeWeightsToSum(filled, criterionIds, MARBLE_TARGET);
	}
	return next;
}

import type { AppSnapshot, ProfileId } from "@portugal/domain-shared";
import { computePlotScores } from "@portugal/domain-shared";

import { sortPlotsByProfile } from "./sort-plots-by-profile";

/** Rank (1 = best) of each plot under a given profile. */
export function plotRanksByProfile(snapshot: AppSnapshot): Record<ProfileId, Record<string, number>> {
	const out: Record<string, Record<string, number>> = {};
	for (const profile of snapshot.activeConfig.profiles) {
		const sorted = sortPlotsByProfile(snapshot.plots, snapshot, profile.id);
		const map: Record<string, number> = {};
		sorted.forEach((plot, index) => {
			map[plot.id] = index + 1;
		});
		out[profile.id] = map;
	}
	return out as Record<ProfileId, Record<string, number>>;
}

/** Sum of ranks across all profiles (lower = more consistently top-ranked). */
export function plotRankSumAcrossProfiles(snapshot: AppSnapshot): Record<string, number> {
	const byProfile = plotRanksByProfile(snapshot);
	const sums: Record<string, number> = {};
	for (const plot of snapshot.plots) {
		let s = 0;
		for (const profile of snapshot.activeConfig.profiles) {
			s += byProfile[profile.id]?.[plot.id] ?? snapshot.plots.length;
		}
		sums[plot.id] = s;
	}
	return sums;
}

export function averageCriterionScoreAcrossPlots(
	snapshot: AppSnapshot,
	criterionId: string,
): number {
	if (snapshot.plots.length === 0) {
		return 0;
	}
	let sum = 0;
	let n = 0;
	for (const plot of snapshot.plots) {
		const sc = computePlotScores(snapshot.activeConfig, plot.rawMetrics).criterionScores[
			criterionId
		];
		if (sc !== undefined) {
			sum += sc;
			n += 1;
		}
	}
	return n === 0 ? 0 : sum / n;
}

import type { AppSnapshot, PlotRecord, ProfileId } from "@portugal/domain-shared";
import { computePlotScores } from "@portugal/domain-shared";

export function sortPlotsByProfile(
	plots: readonly PlotRecord[],
	snapshot: AppSnapshot,
	profileId: ProfileId,
): PlotRecord[] {
	return [...plots].sort((left, right) => {
		const leftScore =
			computePlotScores(snapshot.activeConfig, left.rawMetrics).profileScores[profileId]
				?.percentage ?? 0;
		const rightScore =
			computePlotScores(snapshot.activeConfig, right.rawMetrics).profileScores[profileId]
				?.percentage ?? 0;
		return rightScore - leftScore;
	});
}

