import type { PlotRawMetricValue, ProfileId } from "@portugal/domain-shared";
import { computePlotScores } from "@portugal/domain-shared";
import { Button, Separator, Slider } from "@portugal/ui";
import { MediaHero, PlotCriterionEditorCard } from "@portugal/ui-lib";
import { ExternalLink, MapPin } from "lucide-react";
import { useCallback, useEffect, useMemo, useState } from "react";

import { useAuth } from "../hooks/use-auth";
import {
	normalizeRawMetricInput,
	saveSnapshot,
	type AppSnapshot,
} from "../lib/plot-storage";
import { DetailPanelShell } from "./detail-panel-chrome";
import {
	PLOT_DETAIL_PANEL_TYPE,
	PROFILE_DETAIL_PANEL_TYPE,
} from "./panel-types";
import { usePanelSnapshot } from "./use-panel-snapshot";
import { usePanelsContext } from "@portugal/ui";
import type { panelRegistry } from "./panel-registry";

export type PlotDetailPanelProps = {
	panelType?: string;
	plotId?: string;
};

function formatRawMetricValue(value: PlotRawMetricValue): string {
	if (typeof value === "number") {
		return String(value);
	}
	if (typeof value === "string") {
		return value;
	}
	if (Array.isArray(value)) {
		return value.join(", ");
	}
	return "—";
}

function upsertPlotInSnapshot(
	snapshot: AppSnapshot,
	plotId: string,
	nextRawMetrics: AppSnapshot["plots"][number]["rawMetrics"],
): AppSnapshot {
	return {
		...snapshot,
		plots: snapshot.plots.map((p) =>
			p.id === plotId ? { ...p, rawMetrics: nextRawMetrics } : p,
		),
	};
}

export function PlotDetailPanel({
	panelType = PLOT_DETAIL_PANEL_TYPE,
	plotId: plotIdProp,
}: PlotDetailPanelProps) {
	const plotId =
		typeof plotIdProp === "string" && plotIdProp.length > 0
			? plotIdProp
			: undefined;
	const { snapshot, loading, error } = usePanelSnapshot();
	const { openPanel } = usePanelsContext<typeof panelRegistry>();
	const { canManageData } = useAuth();
	const [editingMetrics, setEditingMetrics] = useState(false);

	const plot = useMemo(
		() => (plotId && snapshot ? snapshot.plots.find((p) => p.id === plotId) : undefined),
		[plotId, snapshot],
	);

	const [draftRawMetrics, setDraftRawMetrics] = useState(plot?.rawMetrics ?? {});

	useEffect(() => {
		if (plot) {
			setDraftRawMetrics({ ...plot.rawMetrics });
			setEditingMetrics(false);
		}
	}, [plot?.id, plot?.rawMetrics]);

	const openProfile = useCallback(
		(profileId: ProfileId) => {
			openPanel(PROFILE_DETAIL_PANEL_TYPE, { profileId });
		},
		[openPanel],
	);

	const handleSaveMetrics = async () => {
		if (!snapshot || !plotId || !plot) {
			return;
		}
		await saveSnapshot(upsertPlotInSnapshot(snapshot, plotId, draftRawMetrics));
		setEditingMetrics(false);
	};

	if (loading) {
		return (
			<DetailPanelShell title="Plot details" panelType={panelType}>
				<p className="text-muted-foreground">Loading…</p>
			</DetailPanelShell>
		);
	}

	if (error || !snapshot) {
		return (
			<DetailPanelShell title="Plot details" panelType={panelType}>
				<p className="text-destructive">{error ?? "No data."}</p>
			</DetailPanelShell>
		);
	}

	if (!plotId) {
		return (
			<DetailPanelShell title="Plot details" panelType={panelType}>
				<p className="text-muted-foreground">No plot selected.</p>
			</DetailPanelShell>
		);
	}

	if (!plot) {
		return (
			<DetailPanelShell title="Plot details" panelType={panelType}>
				<p className="text-muted-foreground">
					No plot found for id <span className="font-mono">{plotId}</span>.
				</p>
			</DetailPanelShell>
		);
	}

	const scores = computePlotScores(
		snapshot.activeConfig,
		editingMetrics ? draftRawMetrics : plot.rawMetrics,
	);
	const cfg = snapshot.activeConfig;
	const lat = plot.location?.lat;
	const lng = plot.location?.lng;
	const hasCoords =
		typeof lat === "number" &&
		typeof lng === "number" &&
		Number.isFinite(lat) &&
		Number.isFinite(lng);
	const mapsQuery = hasCoords ? `${lat},${lng}` : encodeURIComponent(plot.address || plot.name);
	const googleMapsUrl = `https://www.google.com/maps/search/?api=1&query=${mapsQuery}`;
	const embedSrc = hasCoords
		? `https://maps.google.com/maps?q=${lat},${lng}&z=14&output=embed`
		: undefined;

	return (
		<DetailPanelShell title={plot.name.trim() ? plot.name : "Plot"} panelType={panelType}>
			<div className="flex flex-wrap gap-2">
				<Button type="button" variant="outline" size="sm" asChild>
					<a href={googleMapsUrl} target="_blank" rel="noopener noreferrer">
						<ExternalLink className="mr-1 inline size-3.5" />
						Google Maps
					</a>
				</Button>
				{plot.referenceUrl ? (
					<Button type="button" variant="outline" size="sm" asChild>
						<a href={plot.referenceUrl} target="_blank" rel="noopener noreferrer">
							Listing URL
						</a>
					</Button>
				) : null}
				{canManageData ? (
					<Button
						type="button"
						variant={editingMetrics ? "secondary" : "gradient"}
						size="sm"
						onClick={() => {
							if (editingMetrics) {
								setDraftRawMetrics({ ...plot.rawMetrics });
								setEditingMetrics(false);
							} else {
								setDraftRawMetrics({ ...plot.rawMetrics });
								setEditingMetrics(true);
							}
						}}
					>
						{editingMetrics ? "Cancel edit" : "Edit raw metrics"}
					</Button>
				) : null}
				{editingMetrics && canManageData ? (
					<Button type="button" size="sm" onClick={() => void handleSaveMetrics()}>
						Save metrics
					</Button>
				) : null}
			</div>

			<MediaHero alt={plot.name.trim() ? plot.name : "Plot"} src={undefined} />

			<div className="space-y-2">
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Map
				</p>
				{embedSrc ? (
					<iframe
						title="Plot location"
						className="aspect-video w-full rounded-xl border-0 ring-1 ring-border/30"
						src={embedSrc}
						loading="lazy"
						referrerPolicy="no-referrer-when-downgrade"
					/>
				) : (
					<div className="flex flex-col items-center justify-center gap-2 rounded-xl bg-muted/40 py-8 text-center text-xs text-muted-foreground ring-1 ring-border/20">
						<MapPin className="size-8 opacity-50" />
						<p>Add latitude and longitude in plot metadata to embed a map.</p>
						<Button type="button" variant="link" size="sm" className="h-auto p-0" asChild>
							<a href={googleMapsUrl} target="_blank" rel="noopener noreferrer">
								Open Google Maps for this address
							</a>
						</Button>
					</div>
				)}
			</div>

			<dl className="grid gap-2 text-xs sm:grid-cols-2">
				<dt className="text-muted-foreground">Address</dt>
				<dd className="font-medium">{plot.address || "—"}</dd>
				<dt className="text-muted-foreground">Region</dt>
				<dd>{plot.region ?? "—"}</dd>
				<dt className="text-muted-foreground">Municipality</dt>
				<dd>{plot.municipality ?? "—"}</dd>
				<dt className="text-muted-foreground">Coordinates</dt>
				<dd className="font-mono text-[11px]">
					{hasCoords ? `${lat.toFixed(5)}, ${lng.toFixed(5)}` : "—"}
				</dd>
				<dt className="text-muted-foreground">Asking (EUR)</dt>
				<dd>
					{plot.askingPriceEur !== undefined
						? plot.askingPriceEur.toLocaleString()
						: "—"}
				</dd>
				<dt className="text-muted-foreground">KO status</dt>
				<dd>{plot.koStatus ?? "—"}</dd>
				<dt className="text-muted-foreground">Buildable</dt>
				<dd>
					{plot.buildableYn === undefined
						? "—"
						: plot.buildableYn
							? "Yes"
							: "No"}
				</dd>
				<dt className="text-muted-foreground">Road access</dt>
				<dd>
					{plot.roadAccessYn === undefined
						? "—"
						: plot.roadAccessYn
							? "Yes"
							: "No"}
				</dd>
				<dt className="text-muted-foreground">Basic utilities</dt>
				<dd>
					{plot.utilitiesBasicYn === undefined
						? "—"
						: plot.utilitiesBasicYn
							? "Yes"
							: "No"}
				</dd>
			</dl>
			{plot.notes ? (
				<div>
					<p className="text-xs font-medium text-muted-foreground">Notes</p>
					<p className="mt-1 whitespace-pre-wrap text-foreground/90">{plot.notes}</p>
				</div>
			) : null}

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Scores by investment profile
				</p>
				<p className="mt-1 text-[11px] text-muted-foreground">
					Open a profile to adjust weights and compare rankings.
				</p>
				<ul className="mt-2 space-y-1">
					{cfg.profiles.map((profile) => {
						const ps = scores.profileScores[profile.id];
						const pct = ps?.percentage ?? 0;
						const wSum = ps?.weightedTotal ?? 0;
						return (
							<li key={profile.id}>
								<button
									type="button"
									className="flex w-full justify-between gap-2 rounded-md bg-muted/30 px-2 py-1.5 text-left text-xs tabular-nums transition-colors hover:bg-muted/50"
									onClick={() => openProfile(profile.id)}
								>
									<span className="truncate font-medium">{profile.name}</span>
									<span className="shrink-0 text-muted-foreground">
										{(pct / 20).toFixed(2)} / 5 · Σw·s {wSum.toFixed(1)}
									</span>
								</button>
							</li>
						);
					})}
				</ul>
			</div>

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Raw metrics & interpreted scores
				</p>
				{editingMetrics && canManageData ? (
					<div className="mt-3 space-y-3">
						{cfg.criteria.map((criterion) => {
							const currentValue = draftRawMetrics[criterion.id];
							const currentScore = scores.criterionScores[criterion.id];
							return (
								<PlotCriterionEditorCard
									key={criterion.id}
									criterionId={criterion.id}
									criterionName={criterion.name}
									inputKind={
										criterion.rule.type === "numeric"
											? "numeric"
											: criterion.rule.type === "qualitative"
												? "qualitative"
												: "multi_select"
									}
									measurementBasis={criterion.measurementBasis}
									score={currentScore}
									value={
										criterion.rule.type === "numeric"
											? typeof currentValue === "number"
												? String(currentValue)
												: ""
											: criterion.rule.type === "qualitative" &&
													typeof currentValue === "string"
												? currentValue
												: ""
									}
									options={
										criterion.rule.type === "qualitative" ||
										criterion.rule.type === "multi_select"
											? Object.keys(criterion.rule.mapping).map((label) => ({
													label,
													value: label,
												}))
											: []
									}
									selectedOptions={
										Array.isArray(currentValue) ? currentValue : []
									}
									onMultiSelectChange={(nextValues) => {
										if (criterion.rule.type !== "multi_select") {
											return;
										}
										setDraftRawMetrics((prev) => ({
											...prev,
											[criterion.id]: nextValues,
										}));
									}}
									onChange={(nextValue) => {
										const storedValue =
											criterion.rule.type === "numeric"
												? normalizeRawMetricInput(
														nextValue,
														criterion.id,
														snapshot.activeConfig,
													)
												: criterion.rule.type === "qualitative"
													? nextValue
													: Array.isArray(currentValue)
														? currentValue
														: [];
										setDraftRawMetrics((prev) => {
											const next = { ...prev };
											if (storedValue === undefined) {
												delete next[criterion.id];
											} else {
												next[criterion.id] = storedValue;
											}
											return next;
										});
									}}
								/>
							);
						})}
					</div>
				) : (
					<ul className="mt-2 space-y-2">
						{cfg.criteria.map((criterion) => {
							const raw = plot.rawMetrics[criterion.id];
							const interpreted = scores.criterionScores[criterion.id];
							return (
								<li
									key={criterion.id}
									className="rounded-md bg-muted/30 px-2 py-1.5 text-xs"
								>
									<div className="flex flex-wrap items-baseline justify-between gap-2">
										<span className="font-medium text-foreground">{criterion.name}</span>
										<span className="tabular-nums text-score-high">
											Score: {interpreted !== undefined ? `${interpreted} / 5` : "—"}
										</span>
									</div>
									<div className="text-muted-foreground">{criterion.measurementBasis}</div>
									<div className="mt-0.5 font-mono text-[11px] text-foreground/90">
										{raw === undefined ? "—" : formatRawMetricValue(raw)}
									</div>
								</li>
							);
						})}
					</ul>
				)}
			</div>
		</DetailPanelShell>
	);
}

