import { usePanelSnapshot } from "./use-panel-snapshot";
import { usePanelsContext } from "@portugal/ui";
import type { panelRegistry } from "./panel-registry";

input.contents:
import type { CriterionId, ProfileId, ProfileWeights } from "@portugal/domain-shared";
import { computePlotScores } from "@portugal/domain-shared";
import { Button, Label, Separator, Slider, usePanelsContext } from "@portugal/ui";
import { RankingsTable, SegmentedProgress } from "@portugal/ui-lib";
import { useCallback, useEffect, useMemo, useState } from "react";

import { useAuth } from "../hooks/use-auth";
import {
	MARBLE_TARGET,
	normalizeAllProfileWeightsToMarbleTarget,
	sumProfileWeights,
} from "../lib/profile-marbles";
import { plotCrossProfileRank, plotRankSumAcrossProfiles } from "../lib/plot-dashboard-metrics";
import { saveSnapshot, type AppSnapshot } from "../lib/plot-storage";
import { sortPlotsByProfile } from "../lib/sort-plots-by-profile";
import type { panelRegistry } from "./panel-registry";
import { DetailPanelShell } from "./detail-panel-chrome";
import {
	PLOT_DETAIL_PANEL_TYPE,
	PROFILE_DETAIL_PANEL_TYPE,
} from "./panel-types";
import { usePanelSnapshot } from "./use-panel-snapshot";

export type ProfileDetailPanelProps = {
	panelType?: string;
	profileId?: string;
};

function categoryWeightSegments(
	snapshot: AppSnapshot,
	profileId: ProfileId,
): { label: string; value: number; colorClass: string }[] {
	const pw = snapshot.activeConfig.profileWeights[profileId];
	if (!pw) {
		return [];
	}
	const byCat = new Map<string, number>();
	for (const c of snapshot.activeConfig.criteria) {
		const w = pw[c.id] ?? 0;
		byCat.set(c.categoryId, (byCat.get(c.categoryId) ?? 0) + w);
	}
	const total = [...byCat.values()].reduce((a, b) => a + b, 0) || 1;
	const colors = [
		"bg-primary",
		"bg-score-high",
		"bg-score-low",
		"bg-primary/80",
	] as const;
	return [...byCat.entries()].slice(0, 8).map(([categoryId, value], i) => ({
		label:
			snapshot.activeConfig.categories.find((c) => c.id === categoryId)?.name ??
			categoryId,
		value: Math.round((value / total) * 100),
		colorClass: colors[i % colors.length] ?? "bg-primary",
	}));
}

export function ProfileDetailPanel({
	panelType = PROFILE_DETAIL_PANEL_TYPE,
	profileId: profileIdProp,
}: ProfileDetailPanelProps) {
	const profileId =
		typeof profileIdProp === "string" && profileIdProp.length > 0
			? profileIdProp
			: undefined;
	const { snapshot, loading, error } = usePanelSnapshot();
	const { openPanel } = usePanelsContext<typeof panelRegistry>();
	const { canManageData } = useAuth();
	const [editingWeights, setEditingWeights] = useState(false);
	const [draftWeights, setDraftWeights] = useState<ProfileWeights>({});

	const profile = useMemo(
		() =>
			profileId && snapshot
				? snapshot.activeConfig.profiles.find((p) => p.id === profileId)
				: undefined,
		[profileId, snapshot],
	);

	const weights = useMemo(() => {
		if (!snapshot || !profileId) {
			return {} as ProfileWeights;
		}
		return snapshot.activeConfig.profileWeights[profileId] ?? {};
	}, [snapshot, profileId]);

	useEffect(() => {
		if (profileId && snapshot) {
			const w = snapshot.activeConfig.profileWeights[profileId] ?? {};
			const filled: ProfileWeights = {};
			for (const c of snapshot.activeConfig.criteria) {
				filled[c.id] = w[c.id] ?? 0;
			}
			setDraftWeights(filled);
			setEditingWeights(false);
		}
	}, [profileId, snapshot]);

	const weightSegments = useMemo(
		() => (snapshot && profileId ? categoryWeightSegments(snapshot, profileId) : []),
		[snapshot, profileId],
	);

	const rankedPlots = useMemo(() => {
		if (!snapshot || !profileId) {
			return [];
		}
		return sortPlotsByProfile(snapshot.plots, snapshot, profileId);
	}, [snapshot, profileId]);

	const rankSums = useMemo(
		() => (snapshot ? plotRankSumAcrossProfiles(snapshot) : {}),
		[snapshot],
	);
	const crossRanks = useMemo(
		() => (snapshot ? plotCrossProfileRank(snapshot) : {}),
		[snapshot],
	);

	const topPlot = rankedPlots[0];
	const topScores = useMemo(() => {
		if (!snapshot || !profileId || !topPlot) {
			return null;
		}
		return computePlotScores(snapshot.activeConfig, topPlot.rawMetrics);
	}, [snapshot, profileId, topPlot]);

	const openPlot = useCallback(
		(id: string) => {
			openPanel(PLOT_DETAIL_PANEL_TYPE, { plotId: id });
		},
		[openPanel],
	);

	const draftMarbleSum = useMemo(() => sumProfileWeights(draftWeights), [draftWeights]);

	const handleSaveWeights = async () => {
		if (!snapshot || !profileId || !canManageData) {
			return;
		}
		const merged: AppSnapshot["activeConfig"]["profileWeights"] = {
			...snapshot.activeConfig.profileWeights,
			[profileId]: draftWeights,
		};
		const normalized = normalizeAllProfileWeightsToMarbleTarget({
			...snapshot.activeConfig,
			profileWeights: merged,
		});
		await saveSnapshot({
			...snapshot,
			activeConfig: {
				...snapshot.activeConfig,
				profileWeights: normalized,
			},
		});
		setEditingWeights(false);
	};

	if (loading) {
		return (
			<DetailPanelShell title="Investment profile" panelType={panelType}>
				<p className="text-muted-foreground">Loading…</p>
			</DetailPanelShell>
		);
	}

	if (error || !snapshot) {
		return (
			<DetailPanelShell title="Investment profile" panelType={panelType}>
				<p className="text-destructive">{error ?? "No data."}</p>
			</DetailPanelShell>
		);
	}

	if (!profileId) {
		return (
			<DetailPanelShell title="Investment profile" panelType={panelType}>
				<p className="text-muted-foreground">No profile selected.</p>
			</DetailPanelShell>
		);
	}

	if (!profile) {
		return (
			<DetailPanelShell title="Investment profile" panelType={panelType}>
				<p className="text-muted-foreground">
					No profile found for id <span className="font-mono">{profileId}</span>.
				</p>
			</DetailPanelShell>
		);
	}

	const rankingRowsTop5 = rankedPlots.slice(0, 5).map((plot, index) => {
		const score = computePlotScores(snapshot.activeConfig, plot.rawMetrics);
		const pct = score.profileScores[profileId]?.percentage ?? 0;
		const tier =
			index === 0 ? ("high" as const) : index < 3 ? ("mid" as const) : ("low" as const);
		const rs = rankSums[plot.id] ?? 0;
		const cr = crossRanks[plot.id] ?? 0;
		return {
			id: plot.id,
			rank: index + 1,
			title: plot.name.trim() ? plot.name : "Plot",
			subtitle: plot.address || "No address yet",
			score: `${(pct / 20).toFixed(2)}`,
			scoreTier: tier,
			breakdown: `Σ ranks ${rs} · cross #${cr}`,
			onNavigate: () => openPlot(plot.id),
		};
	});

	const pwForProfile = snapshot.activeConfig.profileWeights[profileId] ?? {};
	const criterionRows = snapshot.activeConfig.criteria.map((criterion) => {
		const marble = pwForProfile[criterion.id] ?? 0;
		const sc = topScores?.criterionScores[criterion.id];
		const contrib =
			sc !== undefined && marble !== undefined ? sc * marble : undefined;
		return { criterion, marble, sc, contrib };
	});

	const profileScoreBlock = topPlot
		? computePlotScores(snapshot.activeConfig, topPlot.rawMetrics).profileScores[profileId]
		: undefined;

	return (
		<DetailPanelShell title={profile.name} panelType={panelType}>
			<dl className="grid gap-2 text-xs sm:grid-cols-2">
				<dt className="text-muted-foreground">Code</dt>
				<dd className="font-mono">{profile.code}</dd>
				<dt className="text-muted-foreground">Description</dt>
				<dd className="text-foreground/90">{profile.description}</dd>
			</dl>

			<div className="rounded-xl bg-muted/30 p-3 text-xs">
				<p className="font-semibold text-foreground">Top plot under this profile</p>
				{topPlot ? (
					<button
						type="button"
						className="mt-1 w-full text-left text-primary underline"
						onClick={() => openPlot(topPlot.id)}
					>
						{topPlot.name.trim() ? topPlot.name : "Plot"}
					</button>
				) : (
					<p className="mt-1 text-muted-foreground">No plots yet.</p>
				)}
				{profileScoreBlock ? (
					<p className="mt-2 tabular-nums text-muted-foreground">
						Weighted total Σ(w·s):{" "}
						<span className="font-medium text-foreground">
							{profileScoreBlock.weightedTotal.toFixed(1)}
						</span>{" "}
						(of max {profileScoreBlock.maxTotal.toFixed(0)}) ·{" "}
						{(profileScoreBlock.percentage / 20).toFixed(2)} / 5
					</p>
				) : null}
			</div>

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Category weights (share of marbles)
				</p>
				{weightSegments.length > 0 ? (
					<SegmentedProgress segments={weightSegments} className="mt-2" />
				) : (
					<p className="mt-2 text-sm text-muted-foreground">No weights.</p>
				)}
				<p className="mt-2 text-[11px] text-muted-foreground">
					Each profile uses exactly {MARBLE_TARGET} marbles across criteria so scores stay
					comparable across profiles.
				</p>
			</div>

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Top five plots
				</p>
				{rankingRowsTop5.length === 0 ? (
					<p className="mt-2 text-sm text-muted-foreground">No plots to rank.</p>
				) : (
					<RankingsTable
						className="mt-2"
						rows={rankingRowsTop5}
						onOpenDetailPanel={(id) => openPlot(id)}
					/>
				)}
			</div>

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Weighted breakdown (top-ranked plot)
				</p>
				<p className="mt-1 text-[11px] text-muted-foreground">
					Per criterion: marble weight w, interpreted score s (1–5), contribution w·s.
				</p>
				<div className="mt-2 max-h-52 overflow-auto rounded-lg ring-1 ring-border/20">
					<table className="w-full text-left text-[11px]">
						<thead className="sticky top-0 bg-muted/80">
							<tr>
								<th className="p-2 font-medium">Criterion</th>
								<th className="p-2 font-medium tabular-nums">w</th>
								<th className="p-2 font-medium tabular-nums">s</th>
								<th className="p-2 font-medium tabular-nums">w·s</th>
							</tr>
						</thead>
						<tbody>
							{criterionRows.map(({ criterion, marble, sc, contrib }) => (
								<tr key={criterion.id} className="border-t border-border/30">
									<td className="p-2">{criterion.name}</td>
									<td className="p-2 tabular-nums">{marble}</td>
									<td className="p-2 tabular-nums">{sc ?? "—"}</td>
									<td className="p-2 tabular-nums">
										{contrib !== undefined ? contrib.toFixed(1) : "—"}
									</td>
								</tr>
							))}
						</tbody>
					</table>
				</div>
			</div>

			<Separator />

			<div className="flex flex-wrap items-center justify-between gap-2">
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Edit criterion weights
				</p>
				{canManageData ? (
					<div className="flex flex-wrap gap-2">
						<Button
							type="button"
							size="sm"
							variant={editingWeights ? "secondary" : "outline"}
							onClick={() => {
								if (editingWeights) {
									const w = weights;
									const filled: ProfileWeights = {};
									for (const c of snapshot.activeConfig.criteria) {
										filled[c.id] = w[c.id] ?? 0;
									}
									setDraftWeights(filled);
									setEditingWeights(false);
								} else {
									setDraftWeights({
										...Object.fromEntries(
											snapshot.activeConfig.criteria.map((c) => [
												c.id,
												weights[c.id] ?? 0,
											]),
										),
									});
									setEditingWeights(true);
								}
							}}
						>
							{editingWeights ? "Cancel" : "Edit"}
						</Button>
						{editingWeights ? (
							<Button type="button" size="sm" onClick={() => void handleSaveWeights()}>
								Save & normalize marbles
							</Button>
						) : null}
					</div>
				) : (
					<p className="text-[11px] text-muted-foreground">Admin only.</p>
				)}
			</div>
			{editingWeights && canManageData ? (
				<div className="mt-3 space-y-4">
					<p className="text-xs tabular-nums text-muted-foreground">
						Draft sum: {draftMarbleSum} / {MARBLE_TARGET} — on save, weights are rescaled so
						every profile sums to {MARBLE_TARGET}.
					</p>
					{snapshot.activeConfig.criteria.map((criterion) => (
						<div key={criterion.id} className="space-y-1">
							<div className="flex justify-between gap-2 text-xs">
								<Label htmlFor={`w-${criterion.id}`} className="truncate font-medium">
									{criterion.name}
								</Label>
								<span className="shrink-0 tabular-nums text-muted-foreground">
									{draftWeights[criterion.id as CriterionId] ?? 0} marbles
								</span>
							</div>
							<Slider
								id={`w-${criterion.id}`}
								min={0}
								max={MARBLE_TARGET}
								step={1}
								value={[draftWeights[criterion.id as CriterionId] ?? 0]}
								onValueChange={(v) => {
									const n = v[0] ?? 0;
									setDraftWeights((prev) => ({
										...prev,
										[criterion.id]: n,
									}));
								}}
							/>
						</div>
					))}
				</div>
			) : null}

			<Button type="button" variant="outline" size="sm" className="w-full" asChild>
				<a href="/config">Open full config</a>
			</Button>
		</DetailPanelShell>
	);
}

