import type { ProfileId } from "@portugal/domain-shared";
import { computePlotScores } from "@portugal/domain-shared";
import { cn } from "@portugal/ui-lib";

import type { AppSnapshot, PlotRecord } from "../lib/plot-storage";

export type PlotSummaryCardProps = {
	plot: PlotRecord;
	snapshot: AppSnapshot;
	ranksByProfile: Record<ProfileId, Record<string, number>>;
	rankSum: number;
	crossRank: number;
	/** Optional cover image (e.g. listing photo URL when supported). */
	coverImageSrc?: string;
	onOpenDetailPanel: () => void;
	className?: string;
};

const coverAccent = (plotId: string): string => {
	const palette = [
		"from-slate-700 via-slate-600 to-zinc-800",
		"from-emerald-900/90 via-teal-800/80 to-cyan-950",
		"from-indigo-900/90 via-violet-800/80 to-purple-950",
		"from-amber-900/85 via-orange-800/75 to-rose-950",
		"from-sky-900/90 via-blue-800/80 to-slate-950",
	] as const;
	let h = 0;
	for (let i = 0; i < plotId.length; i += 1) {
		h = (h + plotId.charCodeAt(i) * (i + 3)) % 1009;
	}
	return palette[h % palette.length] ?? palette[0];
};

export function PlotSummaryCard({
	plot,
	snapshot,
	ranksByProfile,
	rankSum,
	crossRank,
	coverImageSrc,
	onOpenDetailPanel,
	className,
}: PlotSummaryCardProps) {
	const cfg = snapshot.activeConfig;
	const scores = computePlotScores(cfg, plot.rawMetrics);
	const title = plot.name.trim() ? plot.name : "Plot";
	const locationLine = [plot.municipality, plot.region].filter(Boolean).join(" · ") || "—";
	const accent = coverAccent(plot.id);

	return (
		<button
			type="button"
			onClick={onOpenDetailPanel}
			className={cn(
				"group flex w-full flex-col overflow-hidden rounded-2xl bg-card text-left ring-1 ring-border/35 transition-shadow hover:ring-primary/35 hover:shadow-md focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
				className,
			)}
		>
			<div className="relative aspect-[5/3] w-full shrink-0 overflow-hidden bg-muted">
				{coverImageSrc ? (
					<img
						src={coverImageSrc}
						alt=""
						className="absolute inset-0 size-full object-cover"
						loading="lazy"
					/>
				) : (
					<div
						className={cn(
							"absolute inset-0 bg-gradient-to-br opacity-95",
							accent,
						)}
					/>
				)}
				<div className="absolute inset-0 bg-gradient-to-t from-background/90 via-background/20 to-transparent" />
				<div className="absolute bottom-0 left-0 right-0 p-3 pt-8">
					<p className="line-clamp-2 font-display text-base font-bold leading-tight text-foreground">
						{title}
					</p>
					<p className="mt-0.5 line-clamp-1 text-xs text-muted-foreground">{plot.address || "—"}</p>
				</div>
			</div>

			<div className="flex flex-col gap-2 p-3 text-xs">
				<div className="flex flex-wrap gap-x-4 gap-y-1 text-[11px] text-muted-foreground">
					<span>
						<span className="font-medium text-foreground">Location</span> {locationLine}
					</span>
					{plot.askingPriceEur !== undefined ? (
						<span className="tabular-nums">
							<span className="font-medium text-foreground">Ask</span>{" "}
							{plot.askingPriceEur.toLocaleString()} €
						</span>
					) : null}
				</div>
				<div className="flex flex-wrap gap-3 border-t border-border/40 pt-2 tabular-nums">
					<span>
						<span className="text-muted-foreground">Σ ranks</span>{" "}
						<span className="font-semibold text-foreground">{rankSum}</span>
					</span>
					<span>
						<span className="text-muted-foreground">All profiles</span>{" "}
						<span className="font-semibold text-foreground">#{crossRank}</span>
					</span>
				</div>
				<div>
					<p className="mb-1 text-[0.65rem] font-bold uppercase tracking-wider text-muted-foreground">
						By profile
					</p>
					<ul className="grid grid-cols-1 gap-1 sm:grid-cols-2">
						{cfg.profiles.map((profile) => {
							const rank = ranksByProfile[profile.id]?.[plot.id] ?? "—";
							const pct = scores.profileScores[profile.id]?.percentage ?? 0;
							const outOf5 = (pct / 20).toFixed(2);
							return (
								<li
									key={profile.id}
									className="flex items-baseline justify-between gap-2 rounded-md bg-muted/40 px-2 py-1 tabular-nums ring-1 ring-border/20"
								>
									<span className="min-w-0 truncate font-medium text-foreground">
										{profile.code}
									</span>
									<span className="shrink-0 text-[11px] text-muted-foreground">
										#{rank} · {outOf5}/5
									</span>
								</li>
							);
						})}
					</ul>
				</div>
				<p className="text-[10px] text-muted-foreground group-hover:text-foreground/80">
					Open plot details
				</p>
			</div>
		</button>
	);
}

