import type { ProfileId } from "@portugal/domain-shared";
import { computePlotScores } from "@portugal/domain-shared";
import { Button, Card, CardContent, CardHeader, CardTitle, usePanelsContext } from "@portugal/ui";
import {
  MapPlaceholder,
  PageHeader,
  PillToggle,
  RankingsTable,
  SegmentedProgress,
  StatPair,
  Thumbnail,
} from "@portugal/ui-lib";
import { Link } from "@tanstack/react-router";
import { useMemo, useState } from "react";
import { plotCrossProfileRank, plotRankSumAcrossProfiles } from "#/lib/plot-dashboard-metrics";
import type { AppSnapshot } from "#/lib/plot-storage";
import { MARBLE_TARGET, sumProfileWeights } from "#/lib/profile-marbles";
import { sortPlotsByProfile } from "#/lib/sort-plots-by-profile";
import type { panelRegistry } from "#/panels/panel-registry";
import { PLOT_DETAIL_PANEL_TYPE, PROFILE_DETAIL_PANEL_TYPE } from "#/panels/panel-types";

const TOP_RANK_LIMIT = 5;

function categoryWeightSegments(
  snapshot: AppSnapshot,
  profileId: ProfileId,
): { label: string; value: number; colorClass: string }[] {
  const pw = snapshot.activeConfig.profileWeights[profileId];
  if (!pw) {
    return [];
  }
  const byCat = new Map<string, number>();
  for (const c of snapshot.activeConfig.criteria) {
    const w = pw[c.id] ?? 0;
    byCat.set(c.categoryId, (byCat.get(c.categoryId) ?? 0) + w);
  }
  const total = [...byCat.values()].reduce((a, b) => a + b, 0) || 1;
  const colors = ["bg-primary", "bg-score-high", "bg-score-low", "bg-primary/80"] as const;
  return [...byCat.entries()].slice(0, 8).map(([categoryId, value], i) => ({
    label: snapshot.activeConfig.categories.find((c) => c.id === categoryId)?.name ?? categoryId,
    value: Math.round((value / total) * 100),
    colorClass: colors[i % colors.length] ?? "bg-primary",
  }));
}

const profileAccentClass = (code: string): string => {
  const palette = [
    "from-violet-600/90 to-fuchsia-700/80",
    "from-emerald-600/90 to-teal-700/80",
    "from-amber-600/90 to-orange-700/80",
    "from-sky-600/90 to-blue-800/80",
    "from-rose-600/90 to-red-800/80",
  ] as const;
  let h = 0;
  for (let i = 0; i < code.length; i += 1) {
    h = (h + code.charCodeAt(i) * (i + 1)) % 997;
  }
  return palette[h % palette.length] ?? palette[0];
};

export type PlotProfilesDashboardPageProps = {
  snapshot: AppSnapshot;
};

export function PlotProfilesDashboardPage({ snapshot }: PlotProfilesDashboardPageProps) {
  const { openPanel } = usePanelsContext<typeof panelRegistry>();
  const [rankingWindow, setRankingWindow] = useState<"today" | "weekly">("today");

  const rankSums = useMemo(() => plotRankSumAcrossProfiles(snapshot), [snapshot]);
  const crossRanks = useMemo(() => plotCrossProfileRank(snapshot), [snapshot]);

  const profiles = snapshot.activeConfig.profiles;
  const totalPlots = snapshot.plots.length;

  const openProfilePanel = (profileId: string) => {
    openPanel(PROFILE_DETAIL_PANEL_TYPE, { profileId });
  };

  const openPlotPanel = (plotId: string) => {
    openPanel(PLOT_DETAIL_PANEL_TYPE, { plotId });
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
        <PageHeader
          kicker="Plot analysis"
          title="Profile dashboards"
          subtitle={`Top ${TOP_RANK_LIMIT} plots per investment profile. Cross-profile rank uses Σ ranks (lower is better). ${rankingWindow === "today" ? "Current" : "Weekly"} view is display-only for now.`}
          actions={
            <Button type="button" variant="outline" size="sm" asChild>
              <Link to="/plots">All plots</Link>
            </Button>
          }
        />
        <div className="flex flex-wrap items-center gap-3">
          <PillToggle
            value={rankingWindow}
            onChange={setRankingWindow}
            options={[
              { value: "today", label: "Today" },
              { value: "weekly", label: "Weekly" },
            ]}
          />
          <StatPair label="Profiles" value={profiles.length} valueClassName="text-primary" />
          <StatPair label="Plots" value={totalPlots} valueClassName="text-score-high" />
        </div>
      </div>

      <div className="flex flex-wrap justify-end gap-2">
        <Button type="button" variant="outline" size="sm" asChild>
          <Link to="/config">Modify rules</Link>
        </Button>
      </div>

      {profiles.length === 0 ? (
        <p className="text-sm text-muted-foreground">No investment profiles in config.</p>
      ) : (
        <div className="grid auto-rows-min gap-4 sm:grid-cols-2 2xl:grid-cols-3">
          {profiles.map((profile) => {
            const rankedPlots = sortPlotsByProfile(snapshot.plots, snapshot, profile.id);
            const topRanked = rankedPlots.slice(0, TOP_RANK_LIMIT);
            const weightSegments = categoryWeightSegments(snapshot, profile.id);
            const marbleSum = sumProfileWeights(
              snapshot.activeConfig.profileWeights[profile.id] ?? {},
            );
            const top = topRanked[0];
            const topPct = top
              ? (computePlotScores(snapshot.activeConfig, top.rawMetrics).profileScores[profile.id]
                  ?.percentage ?? 0)
              : 0;
            const avgScoreTopFive =
              topRanked.length === 0
                ? 0
                : topRanked.reduce((acc, plot) => {
                    const pct =
                      computePlotScores(snapshot.activeConfig, plot.rawMetrics).profileScores[
                        profile.id
                      ]?.percentage ?? 0;
                    return acc + pct / 20;
                  }, 0) / topRanked.length;

            const rankingRows = topRanked.map((plot, index) => {
              const score = computePlotScores(snapshot.activeConfig, plot.rawMetrics);
              const pct = score.profileScores[profile.id]?.percentage ?? 0;
              const wSum = score.profileScores[profile.id]?.weightedTotal ?? 0;
              const tier =
                index === 0 ? ("high" as const) : index < 3 ? ("mid" as const) : ("low" as const);
              const rs = rankSums[plot.id] ?? 0;
              const cr = crossRanks[plot.id] ?? 0;
              return {
                id: plot.id,
                rank: index + 1,
                title: plot.name.trim() ? plot.name : "Plot",
                subtitle: plot.address || "No address yet",
                score: (
                  <span className="tabular-nums">
                    {(pct / 20).toFixed(2)}
                    <span className="block text-[10px] font-normal text-muted-foreground">
                      Σw·s {wSum.toFixed(0)}
                    </span>
                  </span>
                ),
                scoreTier: tier,
                breakdown: `Σr ${rs} · all #${cr}`,
                onNavigate: () => {
                  openPlotPanel(plot.id);
                },
              };
            });

            return (
              <article
                key={profile.id}
                className="flex flex-col gap-4 rounded-2xl bg-card/50 p-4 ring-1 ring-border/30"
              >
                <div className="grid gap-4 lg:grid-cols-12">
                  <div
                    className={`relative flex min-h-[140px] cursor-pointer flex-col justify-end overflow-hidden rounded-xl bg-gradient-to-br p-4 text-primary-foreground shadow-inner lg:col-span-5 ${profileAccentClass(profile.code)}`}
                    role="button"
                    tabIndex={0}
                    onClick={() => openProfilePanel(profile.id)}
                    onKeyDown={(event) => {
                      if (event.key === "Enter" || event.key === " ") {
                        event.preventDefault();
                        openProfilePanel(profile.id);
                      }
                    }}
                  >
                    <p className="text-[0.65rem] font-bold uppercase tracking-widest opacity-90">
                      {profile.code}
                    </p>
                    <h2 className="font-display text-xl font-bold leading-tight">{profile.name}</h2>
                    <p className="mt-1 line-clamp-2 text-xs opacity-90">{profile.description}</p>
                    <Button
                      type="button"
                      size="sm"
                      variant="secondary"
                      className="mt-3 w-fit"
                      onClick={(event) => {
                        event.stopPropagation();
                        openProfilePanel(profile.id);
                      }}
                    >
                      Profile detail
                    </Button>
                  </div>
                  <div className="flex gap-2 lg:col-span-3">
                    <div className="flex-1 overflow-hidden rounded-xl ring-1 ring-border/20">
                      <Thumbnail alt="" className="aspect-square w-full" />
                    </div>
                    <div className="flex-1 overflow-hidden rounded-xl ring-1 ring-border/20">
                      <Thumbnail alt="" className="aspect-square w-full" />
                    </div>
                  </div>
                  <div className="flex flex-col gap-2 lg:col-span-4">
                    <MapPlaceholder topSectorLabel={`${profile.name} · heatmap placeholder`} />
                    <div className="flex flex-wrap gap-3 text-xs">
                      <StatPair
                        label="Marbles"
                        value={`${Math.round(marbleSum)}/${MARBLE_TARGET}`}
                        valueClassName="text-primary"
                      />
                      <StatPair
                        label="Leader score"
                        value={top ? (topPct / 20).toFixed(2) : "—"}
                        valueClassName="text-score-high"
                      />
                      <StatPair
                        label={`Top ${TOP_RANK_LIMIT} avg`}
                        value={avgScoreTopFive.toFixed(2)}
                        valueClassName="text-muted-foreground"
                      />
                    </div>
                  </div>
                </div>

                <div className="grid gap-4 lg:grid-cols-2">
                  <Card className="bg-muted/25 ring-1 ring-border/25">
                    <CardHeader className="pb-2">
                      <CardTitle className="font-display text-sm">
                        Weight mix (categories)
                      </CardTitle>
                    </CardHeader>
                    <CardContent>
                      {weightSegments.length > 0 ? (
                        <SegmentedProgress segments={weightSegments} />
                      ) : (
                        <p className="text-xs text-muted-foreground">No weights.</p>
                      )}
                    </CardContent>
                  </Card>
                  <Card className="bg-muted/25 ring-1 ring-border/25">
                    <CardHeader className="pb-2">
                      <CardTitle className="font-display text-sm">Cross-profile context</CardTitle>
                    </CardHeader>
                    <CardContent className="text-xs text-muted-foreground">
                      <p>
                        Each plot gets a rank under every profile.{" "}
                        <span className="font-medium text-foreground">Σ ranks</span> adds those
                        ranks (lower is more consistently strong).{" "}
                        <span className="font-medium text-foreground">All #</span> is rank of that Σ
                        across all plots.
                      </p>
                    </CardContent>
                  </Card>
                </div>

                {rankingRows.length === 0 ? (
                  <p className="text-sm text-muted-foreground">
                    No plots yet. Add a plot on the Plots page to populate rankings.
                  </p>
                ) : (
                  <div className="min-h-0 flex-1 space-y-2">
                    <RankingsTable
                      rows={rankingRows}
                      onOpenDetailPanel={(plotId) => openPlotPanel(plotId)}
                    />
                    {rankedPlots.length > TOP_RANK_LIMIT ? (
                      <p className="text-xs text-muted-foreground">
                        Showing top {TOP_RANK_LIMIT} of {rankedPlots.length} plots for this profile.
                      </p>
                    ) : null}
                  </div>
                )}
              </article>
            );
          })}
        </div>
      )}
    </div>
  );
}

